sp_widget.client_script:
api.controller = function($scope, $location) {
    var c = this;

    // Track whether modal is open
    c.showAdvancedSearch = false;

    /* ==============================
       COLOR OPTIONS CONFIG
       ============================== */
    c.colorOptions = [{
            label: 'White',
            value: 'W',
            icon: 'white'
        },
        {
            label: 'Blue',
            value: 'U',
            icon: 'blue'
        },
        {
            label: 'Black',
            value: 'B',
            icon: 'black'
        },
        {
            label: 'Red',
            value: 'R',
            icon: 'red'
        },
        {
            label: 'Green',
            value: 'G',
            icon: 'green'
        },
        {
            label: 'Colorless',
            value: 'C',
            icon: 'colorless'
        }
    ];

    /* ==============================
    ADVANCED QUERY MODEL
    ============================== */
    c.advQuery = {
        nameRules: [],
        textRules: [],
        flavorRules: [],
        artistRules: [],
        typeRules: [],
        rarityRules: [],

        cmcRules: [],
        priceRules: [],
        priceChangeRules: [],
        powerRules: [],
        toughnessRules: [],
        loyaltyRules: [],

        colors: {}
    };

    /* ==============================
       TEXT FIELD CONFIG
       ============================== */
    c.textFieldConfigs = [
        { label: 'Name', model: 'nameRules', placeholder: 'Card name' },
        { label: 'Text', model: 'textRules', placeholder: 'Oracle / rules text' },
        { label: 'Flavor', model: 'flavorRules', placeholder: 'Flavor text' },
        { label: 'Artist', model: 'artistRules', placeholder: 'Artist name' },
        { label: 'Type', model: 'typeRules', placeholder: 'e.g. legendary, creature, artifact' }
    ];

    /* ==============================
       NUMERIC FIELD CONFIG
       ============================== */
    /* Description: Defines all numeric fields that support
     * operator-based query building with chaining
     * Parameters: None
     * Returns: None
     */

    c.numericFieldConfigs = [
        {
            label: 'CMC',
            model: 'cmcRules',
            step: null // integers only
        },
        {
            label: 'Price',
            model: 'priceRules',
            step: '0.01'
        },
        {
            label: 'Price Change',
            model: 'priceChangeRules',
            step: '0.01'
        },
        {
            label: 'Power',
            model: 'powerRules',
            step: null
        },
        {
            label: 'Toughness',
            model: 'toughnessRules',
            step: null
        },
        {
            label: 'Loyalty',
            model: 'loyaltyRules',
            step: null
        }
    ];

    /* ==============================
       SELECT FIELD CONFIG
       ============================== */
    c.selectFieldConfigs = [
        {
            label: 'Rarity',
            model: 'rarityRules',
            options: [
                { value: 'common', label: 'Common' },
                { value: 'uncommon', label: 'Uncommon' },
                { value: 'rare', label: 'Rare' },
                { value: 'mythic', label: 'Mythic' },
                { value: 'special', label: 'Special' },
            ]
        }
    ];

    /* ==============================
       CARD SCALE (s|m|l)
       ============================== */
    /* Description: Initialize card scale from URL or server-provided data
     * Parameters: None
     * Returns: None
     */
    c.cardScale = (function() {
        var scale = 'm';
        try {
            var qScale = ($location && $location.search && $location.search().c) || null;
            if (!qScale && $scope.data && $scope.data.card_scale) qScale = $scope.data.card_scale;
            if (qScale && ['s', 'm', 'l'].indexOf(qScale) !== -1) scale = qScale;
        } catch (e) {
            scale = ($scope.data && $scope.data.card_scale) || 'm';
        }
        return scale;
    })();

    /* ==============================
       NAVIGATION: Go to specific page
       ============================== */
    /* Description: Updates the URL with a new page parameter to trigger re-query
     * Parameters: [integer] - page: the page number to navigate to
     * Returns: None
     */
    c.goToPage = function(page) {
        if (!page || page < 1) return;

        // Copy current URL parameters
        var params = angular.copy($location.search());

        // Set new page
        params.p = page;

        // Update URL (Service Portal will re-run widget server)
        $location.search(params);
    };

    /* ==============================
       NEXT PAGE
       ============================== */
    /* Description: Navigates to the next page if available
     * Parameters: None
     * Returns: None
     */
    c.nextPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_next) {
            c.goToPage($scope.data.pagination.page + 1);
        }
    };

    /* ==============================
       PREVIOUS PAGE
       ============================== */
    /* Description: Navigates to the previous page if available
     * Parameters: None
     * Returns: None
     */
    c.prevPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_prev) {
            c.goToPage($scope.data.pagination.page - 1);
        }
    };

    /* ==============================
       FIRST PAGE
       ============================== */
    /* Description: Navigates to the first page
     * Parameters: None
     * Returns: None
     */
    c.firstPage = function() {
        c.goToPage(1);
    };

    /* ==============================
       LAST PAGE
       ============================== */
    /* Description: Navigates to the last page
     * Parameters: None
     * Returns: None
     */
    c.lastPage = function() {
        if ($scope.data.pagination) {
            c.goToPage($scope.data.pagination.total_pages);
        }
    };

    /* ==============================
       SEARCH FUNCTION
       ============================== */
    /* Description: Updates the URL with the search query and resets page to 1
     * Parameters: None
     * Returns: None
     */
    c.submitSearch = function() {
        var params = angular.copy($location.search());

        params.q = c.searchQuery; // set search query
        params.p = 1; // reset page to first

        $location.search(params); // triggers server reload with new query
    };

    /* ==============================
       TOGGLE ADVANCED SEARCH
       ============================== */
    /* Description: Opens or closes the advanced search modal
     * Parameters: None
     * Returns: None
     */
    c.toggleAdvancedSearch = function() {
        c._populateFromParsed(c.data.query);
        c.showAdvancedSearch = !c.showAdvancedSearch;


    };

    /* ==============================
       POPULATE FROM PARSED QUERY
       ============================== */
    /* Description: Parses query string and hydrates advanced search UI
     * Parameters:
     *  - query (String): query string from URL
     * Returns: None
     */

    c._populateFromParsed = function(query) {

        if (!query) return;

        c.advQuery = {
            nameRules: [],
            textRules: [],
            flavorRules: [],
            artistRules: [],
            typeRules: [],
            rarityRules: [],
            cmcRules: [],
            priceRules: [],
            priceChangeRules: [],
            powerRules: [],
            toughnessRules: [],
            loyaltyRules: [],
            colors: {}
        };

        var parsed = query.split(';');

        parsed.forEach(function(pair) {

            var parts = pair.split(':');
            if (parts.length !== 2) return;

            var key = parts[0].trim();
            var rawValue = parts[1].trim();

            // Decode connectors
            var value = rawValue
                .replace(/%26%26/g, '&&')
                .replace(/%7C%7C/g, '||');

            /* ==============================
               COLORS (UNCHANGED)
               ============================== */
            if (key === 'color') {
                value.split(',').forEach(function(code) {
                    var k = code.trim();
                    if (k) {
                        c.advQuery.colors[k] = true;
                    }
                });
                return;
            }

            /* ==============================
               NUMERIC FIELDS
               ============================== */
            var numericMap = {
                cmc: 'cmcRules',
                price: 'priceRules',
                price_change: 'priceChangeRules',
                power: 'powerRules',
                toughness: 'toughnessRules',
                loyalty: 'loyaltyRules'
            };

            if (numericMap[key]) {

                var rules = [];
                var tokens = value.split(/(&&|\|\|)/); // keep connectors

                var currentConnector = null;

                tokens.forEach(function(token) {

                    if (token === '&&' || token === '||') {
                        currentConnector = token;
                        return;
                    }

                    // Extract operator + value
                    var match = token.match(/(<=|>=|=|<|>)(.*)/);
                    if (!match) return;

                    var operator = match[1];
                    var num = Number(match[2]);

                    if (isNaN(num)) return;

                    rules.push({
                        operator: operator,
                        value: num,
                        connector: currentConnector || '&&'
                    });

                    currentConnector = null;
                });

                c.advQuery[numericMap[key]] = rules;
                return;
            }

            /* ==============================
               TEXT / SELECT FIELDS
               ============================== */
            var textMap = {
                name: 'nameRules',
                text: 'textRules',
                flavor: 'flavorRules',
                artist: 'artistRules',
                type: 'typeRules',
                rarity: 'rarityRules'
            };

            if (textMap[key]) {

                var rules = [];
                var tokens = value.split(/(&&|\|\|)/);

                var currentConnector = null;

                tokens.forEach(function(token) {

                    if (token === '&&' || token === '||') {
                        currentConnector = token;
                        return;
                    }

                    var decoded = decodeURIComponent(token.trim());

                    if (!decoded) return;

                    rules.push({
                        value: decoded,
                        connector: currentConnector || '&&'
                    });

                    currentConnector = null;
                });

                c.advQuery[textMap[key]] = rules;
            }

        });

        /* ==============================
           FALLBACK: ENSURE AT LEAST ONE RULE
           ============================== */
        [
            'nameRules','textRules','flavorRules','artistRules',
            'typeRules','rarityRules',
            'cmcRules','priceRules','priceChangeRules','powerRules','toughnessRules','loyaltyRules'
        ].forEach(function(field) {
            if (!c.advQuery[field] || !c.advQuery[field].length) {
                c.addRule(field);
            }
        });
    };

    /* ==============================
       ADD RULE
       ============================== */
    /* Description: Adds a new rule (numeric or text)
    * Parameters:
    *  - field (String)
    * Returns: None
    */

    c.addRule = function(field) {
        let isNumeric = field.indexOf('Rules') > -1 &&
            ['cmcRules','priceRules','priceChangeRules','powerRules','toughnessRules','loyaltyRules'].includes(field);

        c.advQuery[field].push(isNumeric ? {
            operator: '>=',
            value: '',
            connector: '&&'
        } : {
            value: '',
            connector: '&&'
        });
    };


    /* ==============================
       REMOVE RULE
       ============================== */
    /* Description: Removes a condition from a field's advanced query rules.
     *              If removing the first condition, clears all subsequent AND/OR connectors
     *              and leaves only the remaining values intact. Prevents orphaned connectors.
     * Parameters:
     *   - fieldName [string]: the field to remove a rule from
     *   - index [number]: the index of the condition to remove
     * Returns: None
     */

    c.removeRule = function(fieldName, index) {
        if (!c.advQuery[fieldName] || !c.advQuery[fieldName].length) return;

        // Remove the rule at the given index
        c.advQuery[fieldName].splice(index, 1);

        // Approach #1: If first rule is removed, clear all remaining connectors
        if (index === 0 && c.advQuery[fieldName].length > 0) {
            c.advQuery[fieldName].forEach(rule => {
                rule.connector = null;
            });
        }

        // If no conditions remain, add an empty placeholder for user convenience
        if (c.advQuery[fieldName].length === 0) {
            c.advQuery[fieldName].push({ value: '', connector: null, operator: '=' });
        }
    };

    /* ==============================
       BUILD NUMERIC QUERY
       ============================== */
    /* Description: Converts rule array into encoded query string
     * Parameters:
     *  - fieldName (String): API field name (e.g., 'cmc')
     *  - rules (Array): Rule objects
     * Returns:
     *  - String | null
     */

    c.buildNumericQuery = function(fieldName, rules) {
        if (!rules || !rules.length) return null;

        let expression = '';

        rules.forEach(function(rule, index) {
            if (!rule.value && rule.value !== 0) return;

            let part = rule.operator + rule.value;

            if (index > 0) {
                let connector = rule.connector || '&&';

                // CRITICAL: encode connectors
                if (connector === '&&') {
                    expression += '%26%26';
                } else if (connector === '||') {
                    expression += '%7C%7C';
                }
            }

            expression += part;
        });

        return expression ? fieldName + ':' + expression : null;
    };

    /* ==============================
       BUILD TEXT QUERY
       ============================== */
    /* Description: Builds encoded query string for text/select fields
     * Parameters:
     *  - fieldName (String)
     *  - rules (Array)
     * Returns:
     *  - String | null
     */

    c.buildTextQuery = function(fieldName, rules) {
        if (!rules || !rules.length) return null;

        let expression = '';

        rules.forEach(function(rule, index) {
            if (!rule.value) return;

            if (index > 0) {
                let connector = rule.connector || '&&';

                if (connector === '&&') {
                    expression += '%26%26';
                } else if (connector === '||') {
                    expression += '%7C%7C';
                }
            }

            expression += rule.value;
        });

        return expression ? fieldName + ':' + expression : null;
    };

    /* ==============================
       GET HUMAN READABLE QUERY
       ============================== */
    /* Description: Converts the raw query string into a human-readable version
     * Parameters: [string] rawQuery - raw URL query (e.g., name:Aerith%7C%7CAb)
     * Returns: [string] - human-readable query
     */

    c.getReadableQuery = function(rawQuery) {
        console.log('Raw query:', rawQuery);
        if (!rawQuery) return '';

        // Handle if passed object instead of string
        if (typeof rawQuery === 'object') {
            rawQuery = rawQuery.q || '';
        }

        // Double decode
        let decoded = decodeURIComponent(decodeURIComponent(rawQuery));

        // Split into key:value parts
        let parts = decoded.split(';');

        let humanParts = parts.map(part => {
            if (!part) return '';
            let [key, value] = part.split(':');
            if (!value) return part; // fallback

            // Replace logical operators
            value = value.replace(/&&/g, ' AND ').replace(/\|\|/g, ' OR ');

            return `${key}: ${value}`;
        });

        return humanParts.join('; ');
    };

    /* ==============================
       SUBMIT ADVANCED SEARCH
       ============================== */
    /* Description: Builds advanced query string with support for
     * complex numeric expressions and applies it to URL params
     * Parameters: None
     * Returns: None
     */
    c.submitAdvancedSearch = function() {
        var params = angular.copy($location.search());

        let queryParts = [];

        // TEXT FIELDS
        [
            { name: 'name', rules: c.advQuery.nameRules },
            { name: 'text', rules: c.advQuery.textRules },
            { name: 'flavor', rules: c.advQuery.flavorRules },
            { name: 'artist', rules: c.advQuery.artistRules },
            { name: 'type', rules: c.advQuery.typeRules },
            { name: 'rarity', rules: c.advQuery.rarityRules }
        ].forEach(function(field) {
            let result = c.buildTextQuery(field.name, field.rules);
            if (result) queryParts.push(result);
        });

        // NUMERIC FIELDS
        let numericFields = [
            { name: 'cmc', rules: c.advQuery.cmcRules },
            { name: 'price', rules: c.advQuery.priceRules },
            { name: 'price_change', rules: c.advQuery.priceChangeRules },
            { name: 'power', rules: c.advQuery.powerRules },
            { name: 'toughness', rules: c.advQuery.toughnessRules },
            { name: 'loyalty', rules: c.advQuery.loyaltyRules }
        ];

        numericFields.forEach(function(field) {
            let result = c.buildNumericQuery(field.name, field.rules);
            if (result) queryParts.push(result);
        });

        // COLORS
        let selectedColors = Object.keys(c.advQuery.colors)
            .filter(key => c.advQuery.colors[key]);

        if (selectedColors.length) {
            queryParts.push('color:' + selectedColors.join(','));
        }

        params.q = queryParts.join(';');
        params.p = 1;

        // DEBUG MODE (toggle via URL: &debug=true)
        if ($location.search().debug === 'true') {
            console.log('[MTG Advanced Search] Query:', params.q);
        }

        $location.search(params);
        c.showAdvancedSearch = false;
    };
}

sp_widget.script:
(function() {

    /* ==============================
     * CONSTANTS
     * ============================== */
    const PARAMS = {
        DEBUG: 'db',
        DEBUG_METHODS: 'dbm'
    };

    /* ==============================
     * PARAM HELPERS
     * ============================== */
    function getStringParam(name, defaultValue) {
        var val = $sp.getParameter(name);
        return val ? val.toString() : defaultValue;
    }

    /* ==============================
     * USER CONTEXT
     * ============================== */
    const isLoggedIn = gs.getUserID() !== '';
    const isAdmin = gs.hasRole('admin');

    /* ==============================
     * DEBUG PARAMS
     * ============================== */
    const rawDebug = getStringParam(PARAMS.DEBUG, 'false');
    const rawDebugIgnoreMethods = getStringParam(PARAMS.DEBUG_METHODS, '');

    const debugEnabled = (
        (rawDebug === 'true' || rawDebug === '1') &&
        isLoggedIn &&
        isAdmin
    );

    const DebugIgnoreMethods = debugEnabled ? rawDebugIgnoreMethods : '';

    /* ==============================
     * SERVICES INIT
     * ============================== */
    const MTG_CONSTANTS = new x_759224_magic_c_0.mtg_constants(debugEnabled, DebugIgnoreMethods);
    const PORTAL_UTILS = new x_759224_magic_c_0.mtg_portal_utils(debugEnabled, DebugIgnoreMethods, $sp, MTG_CONSTANTS);

    /* ==============================
     * CONFIG
     * ============================== */
    const CONFIG = {
        table: MTG_CONSTANTS.tables.CARDS,
        search_fields: ['name'],
        fields: ['name', 'short_description', 'sys_created_on'],
        order_by: 'name'
    };

    /* ==============================
     * EXECUTION
     * ============================== */
    let countRes = PORTAL_UTILS.getCount(CONFIG.table, CONFIG.search_fields);
    let queryRes = PORTAL_UTILS.queryTable(CONFIG);
    // expose parsed query for client-side pre-population of advanced modal
    let parsedQueryRes = PORTAL_UTILS.parseQuery();
    let humanReadableQueryRes = PORTAL_UTILS.toHumanReadableQuery();
    if (humanReadableQueryRes.success) {
        data.human_readable_query = humanReadableQueryRes.record.human_readable;
    }else{
		data.human_readable_query = data.query;
	}
    let paginationRes = PORTAL_UTILS.getPagination(countRes.record);

    // Card scale param (c): s | m | l. Expose to client in `data.card_scale`.
    var rawScale = getStringParam('c', 'm');
    var cardScale = ['s', 'm', 'l'].indexOf(rawScale) !== -1 ? rawScale : 'm';
    if (debugEnabled) PORTAL_UTILS.log('init', 'card_scale=' + cardScale);

    /* ==============================
     * RESPONSE MAPPING
     * ============================== */
	data.records = queryRes.record || [];
    data.pagination = paginationRes.record || {};
    data.query = PORTAL_UTILS.query;
    data.parsedQuery = parsedQueryRes.record || {};
    data.card_scale = cardScale;
    data.debug = PORTAL_UTILS.debug;
	data.theme = gs.getUser().theme;


    /* ==============================
     * OPTIONAL ERROR SURFACING
     * ============================== */
    data.errors = [];

    if (!countRes.success) data.errors.push(countRes.message);
    if (!queryRes.success) data.errors.push(queryRes.message);
    if (!paginationRes.success) data.errors.push(paginationRes.message);

})();
